   <div id="info-departamento" class="ventana-emergente">
        <h3 id="depto-nombre">Cargando...</h3>
        <p class="estado-servidor" id="servidor-mensaje"></p>
        
        <div class="datos-hídricos">
            <div class="dato">Contaminación Agua: <span id="depto-contaminacion">--</span>%</div>
            <div class="dato">Consumo Total: <span id="depto-consumo">--</span> m³</div>
            <div class="dato">Calidad de Aire (AQI): <span id="depto-aire">--</span></div>
            <div class="dato">Basura Mensual: <span id="depto-basura">--</span> Ton</div>
        </div>
        
        <div style="margin-top: 15px; text-align: center;">
            <a href="#" id="btn-detalles" style="display:inline-block; padding:8px 15px; background:#005f73; color:white; text-decoration:none; border-radius:5px; font-weight:bold; width: 100%;">Ver Informe Completo</a>
        </div>
    </div>

  <script>
        document.addEventListener('DOMContentLoaded', () => {
            // Seleccionamos todos los departamentos dentro del SVG
            const departamentos = document.querySelectorAll('.contenedor-mapa-svg svg path');
            const ventanaEmergente = document.getElementById('info-departamento');
            
            // Elementos de texto dentro de la ventana
            const tituloNombre = document.getElementById('depto-nombre');
            const mensajeServidor = document.getElementById('servidor-mensaje');
            const textoContaminacion = document.getElementById('depto-contaminacion');
            const textoConsumo = document.getElementById('depto-consumo');
            
            // PARTE A: Los nuevos elementos de Aire y Basura
            const textoAire = document.getElementById('depto-aire');
            const textoBasura = document.getElementById('depto-basura');

            departamentos.forEach(depto => {
                depto.addEventListener('click', async (evento) => {
                    // Obtenemos el nombre del departamento
                    let nombreDepartamento = depto.getAttribute('name');
                    if(!nombreDepartamento) {
                        nombreDepartamento = depto.getAttribute('id');
                    }
                    if(!nombreDepartamento) return; 

                    // Posicionar la ventana
                    ventanaEmergente.style.left = (evento.pageX + 15) + 'px';
                    ventanaEmergente.style.top = (evento.pageY + 15) + 'px';
                    ventanaEmergente.style.display = 'block';

                    // PARTE B: Limpiar los textos mientras carga el servidor
                    tituloNombre.textContent = nombreDepartamento;
                    mensajeServidor.textContent = "Conectando al servidor...";
                    textoContaminacion.textContent = "--";
                    textoConsumo.textContent = "--";
                    textoAire.textContent = "--";
                    textoBasura.textContent = "--";

                    // Configuración del botón "Ver Informe Completo"
                    let btnDetalles = document.getElementById('btn-detalles');
                    if (!btnDetalles) {
                        btnDetalles = document.createElement('a');
                        btnDetalles.id = 'btn-detalles';
                        btnDetalles.style.cssText = "display:block; margin-top:15px; padding:8px 15px; background:#005f73; color:white; text-align:center; text-decoration:none; border-radius:5px; font-weight:bold;";
                        btnDetalles.textContent = "Ver Informe Completo";
                        ventanaEmergente.appendChild(btnDetalles);
                    }
                    btnDetalles.onclick = null; 
                    btnDetalles.href = "departamento.php?nombre=" + encodeURIComponent(nombreDepartamento);

                    try {
                        // Consultamos los datos a la BD
                        const respuesta = await fetch(`api_mapa.php?departamento=${encodeURIComponent(nombreDepartamento)}`);
                        if (!respuesta.ok) throw new Error('No se pudo conectar con el servidor.');
                        
                        const datos = await respuesta.json();

                        if (datos.exito) {
                            // PARTE C: Pegar los datos de la base de datos en la pantalla
                            mensajeServidor.textContent = ""; 
                            textoContaminacion.textContent = datos.contaminacion;
                            textoConsumo.textContent = datos.consumo;
                            textoAire.textContent = datos.aire;
                            textoBasura.textContent = datos.basura;
                            
                            // Efecto visual de selección en rojo
                            departamentos.forEach(d => d.style.fill = ""); 
                            depto.style.fill = "#ae2012"; 
                        } else {
                            // Si el departamento no tiene datos
                            mensajeServidor.textContent = datos.error; 
                            textoContaminacion.textContent = "--";
                            textoConsumo.textContent = "--";
                            textoAire.textContent = "--";
                            textoBasura.textContent = "--";
                        }
                    } catch (error) {
                        // Si hay un error de conexión
                        console.error('Error al obtener datos:', error);
                        mensajeServidor.textContent = "Error al conectar con el servidor.";
                        textoContaminacion.textContent = "--";
                        textoConsumo.textContent = "--";
                        textoAire.textContent = "--";
                        textoBasura.textContent = "--";
                    }
                });
            });

            // Si el usuario hace clic fuera del mapa, escondemos la ventana
            document.addEventListener('click', (evento) => {
                if (!evento.target.closest('.contenedor-mapa-svg svg') && !evento.target.closest('.ventana-emergente')) {
                    ventanaEmergente.style.display = 'none';
                    departamentos.forEach(d => d.style.fill = ""); 
                }
            });
        });

        // ==========================================
            // LÓGICA DEL BUSCADOR DE DEPARTAMENTOS
            // ==========================================
            const btnAbrirModal = document.getElementById('btn-abrir-buscador');
            const modalBuscador = document.getElementById('modal-buscador');
            const btnCerrarModal = document.getElementById('btn-cerrar-modal');
            const inputBusqueda = document.getElementById('input-busqueda');
            const btnBuscar = document.getElementById('btn-buscar-depto');
            const errorBusqueda = document.getElementById('error-busqueda');

            // Diccionario inteligente (No importa si escriben sin tildes)
            const diccionarioDepartamentos = {
                "alta verapaz": "Alta Verapaz", "baja verapaz": "Baja Verapaz",
                "chimaltenango": "Chimaltenango", "chiquimula": "Chiquimula",
                "el progreso": "El Progreso", "escuintla": "Escuintla",
                "guatemala": "Guatemala", "huehuetenango": "Huehuetenango",
                "izabal": "Izabal", "jalapa": "Jalapa", "jutiapa": "Jutiapa",
                "peten": "Petén", "quetzaltenango": "Quetzaltenango",
                "quiche": "Quiché", "retalhuleu": "Retalhuleu",
                "sacatepequez": "Sacatepéquez", "san marcos": "San Marcos",
                "santa rosa": "Santa Rosa", "solola": "Sololá",
                "suchitepequez": "Suchitepéquez", "totonicapan": "Totonicapán",
                "zacapa": "Zacapa"
            };

            // 1. Abrir Modal
            if (btnAbrirModal) {
                btnAbrirModal.addEventListener('click', (e) => {
                    e.preventDefault();
                    modalBuscador.style.display = 'block';
                    inputBusqueda.value = ""; // Limpiar busquedas pasadas
                    errorBusqueda.style.display = 'none'; // Ocultar errores
                    setTimeout(() => inputBusqueda.focus(), 100); // Activar teclado
                });
            }

            // 2. Cerrar Modal (con la X o dando clic afuera)
            if (btnCerrarModal) {
                btnCerrarModal.addEventListener('click', () => modalBuscador.style.display = 'none');
            }
            window.addEventListener('click', (e) => {
                if (e.target === modalBuscador) {
                    modalBuscador.style.display = 'none';
                }
            });

            // 3. Ejecutar la búsqueda
            function ejecutarBusqueda() {
                // Quitar espacios extra, pasar a minúsculas y quitar tildes
                let textoLimpio = inputBusqueda.value.trim().normalize("NFD").replace(/[\u0300-\u036f]/g, "").toLowerCase();
                
                if (textoLimpio === "") return;

                if (diccionarioDepartamentos[textoLimpio]) {
                    // Si existe, armamos la URL correcta y redireccionamos
                    let nombreOficial = diccionarioDepartamentos[textoLimpio];
                    window.location.href = `departamento.php?nombre=${encodeURIComponent(nombreOficial)}`;
                } else {
                    // Mostrar error si lo escribió mal
                    errorBusqueda.style.display = 'block';
                }
            }

            // Activar búsqueda al dar clic al botón o presionar ENTER
            if (btnBuscar) btnBuscar.addEventListener('click', ejecutarBusqueda);
            if (inputBusqueda) {
                inputBusqueda.addEventListener('keypress', (e) => {
                    if (e.key === 'Enter') ejecutarBusqueda();
                });
            }

           // ==========================================
            // 1. LÓGICA DE MODO OSCURO 100% AUTOMÁTICO
            // ==========================================
            const body = document.body;
            
            // Le preguntamos al sistema operativo su preferencia de color
            const preferenciaSistema = window.matchMedia('(prefers-color-scheme: dark)');

            // Función que activa o desactiva la clase según el sistema
            function aplicarTemaAutomatico(evento) {
                if (evento.matches) {
                    body.classList.add('dark-mode');
                } else {
                    body.classList.remove('dark-mode');
                }
            }

            // 1. Ejecutar inmediatamente al cargar la página
            aplicarTemaAutomatico(preferenciaSistema);

            // 2. Quedarse escuchando por si el usuario cambia el tema de su celular/PC mientras navega
            preferenciaSistema.addEventListener('change', aplicarTemaAutomatico);
    </script>
    

</body>
</html>